import{_ as a,o as t,c as n,a2 as s}from"./chunks/framework.CndDaRl3.js";const m=JSON.parse('{"title":"AI Agent Development Flow","description":"","frontmatter":{},"headers":[],"relativePath":"fork/agent-development.md","filePath":"fork/agent-development.md","lastUpdated":1776112082000}'),o={name:"fork/agent-development.md"};function i(l,e,r,d,p,h){return t(),n("div",null,[...e[0]||(e[0]=[s(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /react-starter-kit/fork/agent-development.md for this page in Markdown format</div><h1 id="ai-agent-development-flow" tabindex="-1">AI Agent Development Flow <a class="header-anchor" href="#ai-agent-development-flow" aria-label="Permalink to &quot;AI Agent Development Flow&quot;">​</a></h1><p>This fork of React Starter Kit includes a specialized development environment designed to make it safe, fast, and completely collision-free for multiple autonomous AI agents to work on and test the codebase simultaneously.</p><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>When multiple agents or parallel processes try to run <code>bun dev</code> to verify their code changes:</p><ol><li>They often collide on default static ports (e.g., <code>5173</code>, <code>8787</code>).</li><li>If left running indefinitely, these preview servers waste system resources and create orphaned processes.</li><li>Agents often don&#39;t know how to gracefully tear down the development environment after verification.</li></ol><h2 id="the-solution" tabindex="-1">The Solution <a class="header-anchor" href="#the-solution" aria-label="Permalink to &quot;The Solution&quot;">​</a></h2><p>We replaced the standard <code>bun dev</code> command with a smart orchestration script. It behaves normally for human developers, but unlocks specialized superpowers when invoked by an AI agent.</p><h3 id="_1-normal-development-human" tabindex="-1">1. Normal Development (Human) <a class="header-anchor" href="#_1-normal-development-human" aria-label="Permalink to &quot;1. Normal Development (Human)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>For a human developer, this behaves exactly as expected. It binds to the static ports defined in your <code>.env</code> file (<code>5173</code> for Vite, <code>8787</code> for Hono, etc.) and keeps the server running until you manually stop it with <code>Ctrl+C</code>.</p><h3 id="_2-agent-development-proxy-mode" tabindex="-1">2. Agent Development (Proxy Mode) <a class="header-anchor" href="#_2-agent-development-proxy-mode" aria-label="Permalink to &quot;2. Agent Development (Proxy Mode)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">AGENT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>When an agent sets <code>AGENT=1</code>:</p><ul><li><strong>Dynamic Port Allocation:</strong> The script dynamically finds 4 random, available open ports on the host system to run the API, App, and Web workers.</li><li><strong>Reverse Proxy:</strong> It spins up a single entry-point reverse proxy (also on a random open port) that maps everything together exactly as Cloudflare Workers would.</li><li><strong>Inactivity Timeout:</strong> It tracks HTTP traffic hitting the proxy. If 30 seconds pass without any new network requests, the proxy cleanly shuts down all child processes and exits with <code>code 0</code>.</li></ul><p>This makes it extremely safe for agents to spawn preview servers and verify their HTTP responses without leaving messy zombie processes on your machine.</p><h3 id="_3-agent-development-docker-mode" tabindex="-1">3. Agent Development (Docker Mode) <a class="header-anchor" href="#_3-agent-development-docker-mode" aria-label="Permalink to &quot;3. Agent Development (Docker Mode)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">AGENT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> AGENT_RUNTIME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">docker</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>Sometimes agents need complete filesystem isolation or they might accidentally kill a background process they shouldn&#39;t.</p><p>By setting <code>AGENT_RUNTIME=docker</code> alongside <code>AGENT=1</code>:</p><ul><li>A fully isolated <code>node:22-bookworm</code> Docker container is spun up.</li><li>The <code>node_modules</code> from your host macOS/Windows machine are explicitly excluded to ensure the Linux container downloads the correct native binaries for tools like <code>esbuild</code> and <code>workerd</code>.</li><li>Code changes in <code>src/</code> directories are mapped live, so the agent can still make code modifications and instantly see the results in the Dockerized preview server.</li><li>The same 30-second inactivity timeout runs inside the container. Once it shuts down, a host script automatically tears down the container and network volumes to leave zero trace.</li></ul><h2 id="environment-variables-configuration" tabindex="-1">Environment Variables Configuration <a class="header-anchor" href="#environment-variables-configuration" aria-label="Permalink to &quot;Environment Variables Configuration&quot;">​</a></h2><p>These behaviors can be permanently toggled in your <code>.env</code> file instead of passing them inline:</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Enable dynamic port assignment and 30s auto-shutdown</span></span>
<span class="line"><span>AGENT=1</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Run the agent server inside an isolated Docker container</span></span>
<span class="line"><span>AGENT_RUNTIME=docker</span></span></code></pre></div>`,24)])])}const u=a(o,[["render",i]]);export{m as __pageData,u as default};
